#include <stdio.h>
#include <stdlib.h>
typedef struct StackNode {
    int data;
    struct StackNode* next;
} StackNode;
typedef struct {
    StackNode* top;
} Stack;
void push(Stack* stack, int x) {
    StackNode* newNode = (StackNode*)malloc(sizeof(StackNode));
    newNode->data = x;
    newNode->next = stack->top;
    stack->top = newNode;
}
int pop(Stack* stack) {
    if (stack->top == NULL) return -1;
    int x = stack->top->data;
    StackNode* temp = stack->top;
    stack->top = stack->top->next;
    free(temp);
    return x;
}
int peek(Stack* stack) {
    if (stack->top == NULL) return -1;
    return stack->top->data;
}
int isEmpty(Stack* stack) {
    return stack->top == NULL;
}
void queueUsingStacks(int N) {
    Stack inStack, outStack;
    inStack.top = NULL;
    outStack.top = NULL;
    for (int i = 0; i < N; i++) {
        char op[10];
        int x;
        scanf("%s", op);
        if (strcmp(op, "push") == 0) {
            scanf("%d", &x);
            push(&inStack, x);
            printf("None\n");
        } else if (strcmp(op, "pop") == 0) {
            if (outStack.top == NULL) {
                while (inStack.top != NULL) {
                    push(&outStack, pop(&inStack));
                }
            }
            if (outStack.top != NULL) {
                printf("%d\n", pop(&outStack));
            } else {
                printf("-1\n");
            }
        } else if (strcmp(op, "peek") == 0) {
            if (outStack.top == NULL) {
                while (inStack.top != NULL) {
                    push(&outStack, pop(&inStack));
                }
            }
            if (outStack.top != NULL) {
                printf("%d\n", peek(&outStack));
            } else {
                printf("-1\n");
            }
        } else if (strcmp(op, "empty") == 0) {
            if (inStack.top == NULL && outStack.top == NULL) {
                printf("true\n");
            } else {
                printf("false\n");
            }
        }
    }
}
int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int N;
        scanf("%d", &N);
        queueUsingStacks(N);
    }
    return 0;
}

