#include <iostream>
#include <stack>
using namespace std;
class QueueUsingStacks {
public:
    void pushElement(int x) {
        inStack.push(x);
    }
    int popElement() {
        if (outStack.empty()) {
            while (!inStack.empty()) {
                outStack.push(inStack.top());
                inStack.pop();
            }
        }
        if (!outStack.empty()) {
            int x = outStack.top();
            outStack.pop();
            return x;
        } else {
            return -1;
        }
    }
    int peekElement() {
        if (outStack.empty()) {
            while (!inStack.empty()) {
                outStack.push(inStack.top());
                inStack.pop();
            }
        }
        if (!outStack.empty()) {
            return outStack.top();
        } else {
            return -1;
        }
    }
    bool isEmptyResult() {
        return inStack.empty() && outStack.empty();
    }
private:
    stack<int> inStack;
    stack<int> outStack;
};
int main() {
    int T;
    cin >> T;
    for (int i = 0; i < T; i++) {
        int N;
        cin >> N;
        QueueUsingStacks queue;
        for (int j = 0; j < N; j++) {
            string op;
            cin >> op;
            if (op == "push") {
                int x;
                cin >> x;
                queue.pushElement(x);
                cout << "None" << endl;
            } else if (op == "pop") {
                cout << queue.popElement() << endl;
            } else if (op == "peek") {
                cout << queue.peekElement() << endl;
            } else if (op == "empty") {
                cout << (queue.isEmptyResult() ? "true" : "false") << endl;
            }
        }
    }
    return 0;
}

